import { RefObject } from 'react';
import type { CalendarTimeframeState, CalendarTimeframeStoreActions } from './calendar.types.js';
import type { DateTimeInputRef, DateTimeRangePickerRef } from '../../../forms/date-time-range-picker/types.js';
import type { TimeValue } from '../../types/time.js';
import type { TimeErrorKey, Precision } from '../shared.types.js';
/**
 * State slice for the DateTimeRangePicker component.
 * Extends CalendarTimeframeState to inherit calendar state while adding
 * picker-specific state for managing the from/to date-time range inputs.
 * @internal
 */
export type DateTimeRangePickerTimeframeStates = Omit<CalendarTimeframeState, 'calendarValue'> & {
    /** Narrows calendarValue to the range-specific shape, excluding single TimeValue. */
    calendarValue: null | {
        from: TimeValue | null;
        to: TimeValue | null;
    };
    /** Narrows the base precision to exclude 'day' — DateTimeRangePicker does not support day-only precision. */
    precision?: Exclude<Precision, 'day'>;
    /** The current timeframe value with from/to dates being edited in the picker inputs. */
    dateTimeRangePickerTimeframe: null | {
        from: TimeValue | null;
        to: TimeValue | null;
    };
    /** Ref to the "from" input used for post-calendar focus handling. */
    dateTimeFromRef: RefObject<DateTimeInputRef>;
    /** Ref to the DateTimeRangePicker for imperative access (open/close overlay, focus, validation). */
    dateTimeRangePickerRef: RefObject<DateTimeRangePickerRef>;
    /** Current validation error state specific to the picker (e.g., invalid order, out of bounds). */
    dateTimeRangePickerError?: TimeErrorKey;
    /** ISO Format depending on the current locale and precision. */
    formatString?: string;
};
/**
 * Actions slice for the DateTimeRangePicker component.
 * Extends CalendarTimeframeStoreActions to inherit calendar actions while adding
 * picker-specific actions for updating the timeframe from user input.
 * @internal
 */
export type DateTimeRangePickerTimeframeStoreActions = CalendarTimeframeStoreActions & {
    /**
     * Updates the picker timeframe when user edits the from/to inputs. Validates and syncs with calendar.
     * @param value - within the Timeframe null is used to clear that side of the range, while a partial timeframe just overwrites the specified side(s).
     */
    setDateTimeRangePickerTimeframe: (value: Partial<{
        from: TimeValue | null;
        to: TimeValue | null;
    }> | null) => void;
    /**
     * Clears the calendar selection entirely, typically used when a partial value is selected and the overlay is closed without completing a full range selection. This resets both calendar and picker timeframe values to null.
     */
    clearCalendarValue: () => void;
};
/**
 * Combined DateTimeRangePicker store type (state + actions).
 * Use this when consuming the full DateTimeRangePicker store.
 * @internal
 */
export type DateTimeRangePickerTimeframeStore = DateTimeRangePickerTimeframeStates & DateTimeRangePickerTimeframeStoreActions;
